            var ps = string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            var obsolete = m.GetCustomAttribute<ObsoleteAttribute>();
            var obsStr = obsolete != null ? " [OBSOLETE]" : "";
            Console.WriteLine($"{m.Name}{genArgs}({ps}){obsStr}");
        }
